let webSocketServer=null;export function setWebSocketServerForUIProTool(server){webSocketServer=server}export function getWebSocketServerForUIProTool(){return webSocketServer}export function checkWebSocketServerForUIProTool(webSocketServer){if(!webSocketServer){return{valid:!1,data:{isError:!0,content:[{type:"text",text:"Error: WebSocket server not initialized. Please ensure the MCP server is properly configured."}]}}}if(!webSocketServer.isServerRunning()){return{valid:!1,data:{isError:!0,content:[{type:"text",text:"Error: WebSocket server is not running. Please check server status."}]}}}if(0===webSocketServer.getStats().activeConnections){return{valid:!1,data:{isError:!0,content:[{type:"text",text:"Error: No UIPro Figma plugin connection found. Please ensure the UIPro Figma plugin is connected."}]}}}return{valid:!0}}